import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.Bix3-HpO.js";const g=JSON.parse('{"title":"Page Templates","description":"Sikika Page Templates","frontmatter":{"title":"Page Templates","description":"Sikika Page Templates","weight":20,"extra":{"order":20},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/sikika/page-templates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/sikika/page-templates"}],["meta",{"property":"og:title","content":"Page Templates"}],["meta",{"property":"og:description","content":"Sikika Page Templates"}],["meta",{"name":"twitter:title","content":"Page Templates"}],["meta",{"name":"twitter:description","content":"Sikika Page Templates"}]]},"headers":[],"relativePath":"docs/sikika/page-templates.md","filePath":"docs/sikika/page-templates.md"}'),l={name:"docs/sikika/page-templates.md"};function s(r,e,p,n,d,m){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="page-templates" tabindex="-1">Page Templates <a class="header-anchor" href="#page-templates" aria-label="Permalink to &quot;Page Templates&quot;">​</a></h1><p>Sikika comes with several page templates to help you create different types of pages.</p><hr><h3 id="available-templates" tabindex="-1">Available Templates <a class="header-anchor" href="#available-templates" aria-label="Permalink to &quot;Available Templates&quot;">​</a></h3><p>Sikika includes the following page templates:</p><ol><li><strong>Default Template</strong>: Standard page layout with content and sidebar</li><li><strong>Page Sidebar</strong>: Alternative layout with sidebar on the left side</li><li><strong>Sportsbook Sidebar</strong>: Special template for sportsbook review pages with dedicated sidebar (requires Kemoku plugin)</li></ol><h3 id="how-to-use-templates" tabindex="-1">How to Use Templates <a class="header-anchor" href="#how-to-use-templates" aria-label="Permalink to &quot;How to Use Templates&quot;">​</a></h3><ol><li>Create a new page or edit an existing one</li><li>In the page editor, look for the &quot;Page Attributes&quot; section in the sidebar</li><li>Under &quot;Template&quot;, select your desired template from the dropdown</li><li>Update or publish the page</li></ol><h3 id="sportsbook-template" tabindex="-1">Sportsbook Template <a class="header-anchor" href="#sportsbook-template" aria-label="Permalink to &quot;Sportsbook Template&quot;">​</a></h3><p>The Sportsbook template is specifically designed for sportsbook review pages. It includes:</p><ul><li>A dedicated sidebar for sportsbook-specific widgets</li><li>Optimized layout for review content</li><li>Special styling for sportsbook information</li></ul><blockquote><p><strong>Note:</strong> The Sportsbook template is only available when the Kemoku Sportsbook Reviews plugin is installed and activated.</p></blockquote>',12)])])}const h=t(l,[["render",s]]);export{g as __pageData,h as default};
